:setvar DeploymentEnvironment "Development"
:setvar PractitionerDatabase "AcutisPractitioner"
:setvar CommunityDatabase "AcutisCommunity"
IF '$(DeploymentEnvironment)' IN ('Production','Prod') THROW 51000,'Demo reset is forbidden in production.',1;
DECLARE @P uniqueidentifier='11111111-1111-4111-8111-111111111111',@C uniqueidentifier='22222222-2222-4222-8222-222222222222';
DELETE FROM [$(PractitionerDatabase)].dbo.VideoInvitations WHERE TenantId=@P; DELETE FROM [$(PractitionerDatabase)].dbo.VideoConsultations WHERE TenantId=@P; DELETE FROM [$(PractitionerDatabase)].dbo.FormResponses WHERE TenantId=@P; DELETE FROM [$(PractitionerDatabase)].dbo.FormAssignments WHERE TenantId=@P; DELETE FROM [$(PractitionerDatabase)].dbo.FormDefinitions WHERE TenantId=@P; DELETE FROM [$(PractitionerDatabase)].dbo.Assessments WHERE TenantId=@P; DELETE FROM [$(PractitionerDatabase)].dbo.CarePlans WHERE TenantId=@P; DELETE FROM [$(PractitionerDatabase)].dbo.Appointments WHERE TenantId=@P; DELETE FROM [$(PractitionerDatabase)].dbo.Clients WHERE TenantId=@P; DELETE FROM [$(PractitionerDatabase)].dbo.Memberships WHERE TenantId=@P; DELETE FROM [$(PractitionerDatabase)].dbo.Branding WHERE TenantId=@P; DELETE FROM [$(PractitionerDatabase)].dbo.AuditEvents WHERE TenantId=@P; DELETE FROM [$(PractitionerDatabase)].dbo.Tenants WHERE Id=@P;
DELETE FROM [$(CommunityDatabase)].dbo.FormResponses WHERE TenantId=@C; DELETE FROM [$(CommunityDatabase)].dbo.FormAssignments WHERE TenantId=@C; DELETE FROM [$(CommunityDatabase)].dbo.FormDefinitions WHERE TenantId=@C; DELETE FROM [$(CommunityDatabase)].dbo.Appointments WHERE TenantId=@C; DELETE FROM [$(CommunityDatabase)].dbo.Participants WHERE TenantId=@C; DELETE FROM [$(CommunityDatabase)].dbo.Memberships WHERE TenantId=@C; DELETE FROM [$(CommunityDatabase)].dbo.AuditEvents WHERE TenantId=@C; DELETE FROM [$(CommunityDatabase)].dbo.Tenants WHERE Id=@C;
